from flask import Flask, send_file; app = Flask(__name__); app.add_url_rule('/', 'index', lambda: '<html><head><link rel=\"shortcut icon\" href=\"/favicon.ico\" type=\"image/x-icon\"><meta charset=\"utf-8\"></head><body style=\"font-family: sans-serif; text-align: center; margin-top: 50px;\"><h2>¡Funcionando en local y listo para la nube!</h2></body></html>'); app.add_url_rule('/favicon.ico', 'favicon', lambda: send_file('favicon.ico', mimetype='image/x-icon')); app.run(debug=True, port=5002) if __name__ == '__main__' else None
